code.Python3:
import sys
def main():
    data=sys.stdin.buffer.read().split()
    if not data:
        return
    it=iter(data)
    T=int(next(it))
    out=[]
    for _ in range(T):
        N=int(next(it))
        max_h=-float('inf')
        for _ in range(N):
            h=int(next(it))
            if h>max_h:
                max_h=h
        out.append(str(max_h))
    sys.stdout.write('\n'.join(out))
if __name__=='__main__':
    main()

