const fs=require('fs');
const input=fs.readFileSync(0,'utf-8').trim().split(/\s+/);
let idx=0;
const T=Number(input[idx++]);
let res=[];
for(let t=0;t<T;t++){
  const N=Number(input[idx++]);
  let max=-Infinity;
  for(let i=0;i<N;i++){
    const h=Number(input[idx++]);
    if(h>max) max=h;
  }
  res.push(String(max));
}
console.log(res.join('\n'));
